// 提取当前文档的样式模板信息
var doc = Application.ActiveDocument;
var stylesInfo = [];
var paragraphCount = doc.Paragraphs.Count;

for (var i = 1; i <= paragraphCount; i++) {
    var para = doc.Paragraphs.Item(i);
    var text = para.Range.Text.replace(/\r/g, '');
    if (text.trim() === '') continue;

    var styleInfo = {
        text: text.substring(0, 50),
        fontName: para.Range.Font.Name,
        fontSize: para.Range.Font.Size,
        bold: para.Range.Font.Bold,
        italic: para.Range.Font.Italic,
        alignment: para.Alignment,
        firstLineIndent: para.FirstLineIndent,
        lineSpacing: para.LineSpacing,
        spaceBefore: para.SpaceBefore,
        spaceAfter: para.SpaceAfter
    };
    stylesInfo.push(styleInfo);
}

// 简单分类和统计
var styleGroups = {};
for (var i = 0; i < stylesInfo.length; i++) {
    var info = stylesInfo[i];
    var key = info.fontName + '|' + info.fontSize + '|' + info.bold + '|' + info.alignment;
    if (!styleGroups[key]) {
        styleGroups[key] = {count: 0, examples: [], info: info};
    }
    styleGroups[key].count++;
    if (styleGroups[key].examples.length < 2) {
        styleGroups[key].examples.push(info.text);
    }
}

// 生成结果字符串
var result = '✅ 样式模板提取完成！\n\n📄 源文档：样式提取.docx\n📊 共 ' + Object.keys(styleGroups).length + ' 种样式，' + stylesInfo.length + ' 个段落\n\n## 提取的样式详情\n\n';

var keys = Object.keys(styleGroups);
for (var i = 0; i < keys.length; i++) {
    var key = keys[i];
    var group = styleGroups[key];
    var info = group.info;

    result += '### 样式组 ' + (i + 1) + '（' + group.count + '处）\n';
    result += '字体: ' + info.fontName + ' | 字号: ' + info.fontSize + 'pt';
    if (info.bold) result += ' | 加粗';
    if (info.italic) result += ' | 斜体';
    result += ' | 对齐: ';
    if (info.alignment == 0) result += '左对齐';
    else if (info.alignment == 1) result += '居中';
    else if (info.alignment == 2) result += '右对齐';
    else if (info.alignment == 3) result += '两端对齐';

    if (info.firstLineIndent !== 0) {
        result += ' | 首行缩进: ' + (info.firstLineIndent / 28.35).toFixed(1) + '字符';
    }
    if (info.lineSpacing !== 0) {
        result += ' | 行距: ' + info.lineSpacing.toFixed(1) + 'pt';
    }
    if (info.spaceBefore !== 0) {
        result += ' | 段前: ' + info.spaceBefore + 'pt';
    }
    if (info.spaceAfter !== 0) {
        result += ' | 段后: ' + info.spaceAfter + 'pt';
    }
    result += '\n示例: "' + group.examples.join('" | "') + '"\n\n';
}

return result;
